 1→/**
 2→ * Session Upserter — Idempotent DB Adapter
 3→ *
 4→ * Creates or updates an agent_session record in SurrealDB using native UPSERT
 5→ * with the deterministic UUIDv5 session ID from the hash resolver.
 6→ *
 7→ * This replaces the conversation upserter — the proxy groups traces via
 8→ * agent_session (invoked edges), not conversation records.
 9→ *
10→ * Port: (SessionUpsertInput, Dependencies) -> Promise<string | undefined>
11→ * Side effects: SurrealDB writes (boundary adapter)
12→ */
13→
14→import { RecordId } from "surrealdb";
15→import type { Surreal } from "surrealdb";
16→import { log } from "../telemetry/logger";
17→
18→// ---------------------------------------------------------------------------
19→// Types
20→// ---------------------------------------------------------------------------
21→
22→export type SessionUpsertInput = {
23→  readonly sessionId: string;
24→  readonly workspaceId: string;
25→  readonly agent: string;
26→};
27→
28→type SessionUpsertDependencies = {
29→  readonly surreal: Surreal;
30→};
31→
32→// ---------------------------------------------------------------------------
33→// Public API
34→// ---------------------------------------------------------------------------
35→
36→/**
37→ * Upsert an agent_session record from a content-derived hash.
38→ * Returns the session PK (string) on success, undefined on failure.
39→ * Failure never throws -- it logs a warning and returns undefined
40→ * so the caller can proceed without blocking.
41→ */
42→export async function upsertProxySession(
43→  input: SessionUpsertInput,
44→  deps: SessionUpsertDependencies,
45→): Promise<string | undefined> {
46→  const sessionRecord = new RecordId("agent_session", input.sessionId);
47→  const workspaceRecord = new RecordId("workspace", input.workspaceId);
48→
49→  try {
50→    const results = await deps.surreal.query<[Array<{ id: RecordId }>]>(
51→      `UPSERT $sess MERGE {
52→        agent: $agent,
53→        workspace: $workspace,
54→        source: "proxy_hash",
55→        started_at: started_at ?? time::now(),
56→        last_event_at: time::now(),
57→        created_at: created_at ?? time::now()
58→      };`,
59→      {
60→        sess: sessionRecord,
61→        workspace: workspaceRecord,
62→        agent: input.agent,
63→      },
64→    );
65→
66→    const record = results[0]?.[0];
67→    if (record) {
68→      log.info("proxy.session.upserted", "Proxy session upserted via content hash", {
69→        session_id: input.sessionId,
70→        workspace_id: input.workspaceId,
71→      });
72→      return record.id.id as string;
73→    }
74→  } catch (error) {
75→    log.error(
76→      "proxy.session.upsert_failed",
77→      "Failed to upsert proxy session record",
78→      error,
79→    );
80→  }
81→
82→  return undefined;
83→}
84→

  1→import { RecordId, type Surreal } from "surrealdb";
  2→import type { AgentHandle, SpawnAgentFn } from "./spawn-agent";
  3→import type { AgentSpawnConfig } from "./agent-options";
  4→import type { ShellExec } from "./worktree-manager";
  5→import { createWorktree, removeWorktree } from "./worktree-manager";
  6→import type { AssignmentResult } from "./assignment-guard";
  7→import type { AssignmentError, OrchestratorStatus } from "./types";
  8→import { TERMINAL_ORCHESTRATOR_STATUSES } from "./types";
  9→import { startEventBridge, type SdkMessage } from "./event-bridge";
 10→import type { StreamEvent } from "../../shared/contracts";
 11→import type { StallDetectorHandle } from "./stall-detector";
 12→import { getIntentById, updateIntentStatus } from "../intent/intent-queries";
 13→import type { IntentStatus } from "../intent/types";
