  1→/**
  2→ * Session Hash Resolver — Pure Function
  3→ *
  4→ * Derives a deterministic agent session identity from request content
  5→ * using UUIDv5(BRAIN_PROXY_NAMESPACE, system_prompt + NUL + first_user_message).
  6→ *
  7→ * This enables trace grouping via agent_session when no explicit session
  8→ * signal (X-Brain-Session header or Claude Code metadata) is available.
  9→ *
 10→ * Port: SessionHashInput -> SessionHashResult | undefined
 11→ * Side effects: none (pure function)
 12→ */
 13→
 14→import { createHash } from "crypto";
 15→
 16→// ---------------------------------------------------------------------------
 17→// UUIDv5 Namespace for Brain Proxy
 18→// ---------------------------------------------------------------------------
 19→
 20→/** Brain proxy namespace UUID for UUIDv5 generation (randomly generated, fixed). */
 21→const BRAIN_PROXY_NAMESPACE = "a1b2c3d4-e5f6-4a7b-8c9d-0e1f2a3b4c5d";
 22→
 23→/** NUL separator between system prompt and first user message. */
 24→const NUL_SEPARATOR = "\0";
 25→
 26→/** Maximum title length before truncation. */
 27→const MAX_TITLE_LENGTH = 100;
 28→
 29→// ---------------------------------------------------------------------------
 30→// Types
 31→// ---------------------------------------------------------------------------
 32→
 33→export type SessionHashInput = {
 34→  readonly systemPrompt?: string;
 35→  readonly systemPromptBlocks?: ReadonlyArray<{ type: string; text: string }>;
 36→  readonly messages: ReadonlyArray<{ role: string; content: string }>;
 37→};
 38→
 39→export type SessionHashResult = {
 40→  readonly sessionId: string;
 41→  readonly title: string;
 42→};
 43→
 44→// ---------------------------------------------------------------------------
 45→// UUIDv5 Implementation (RFC 4122)
 46→// ---------------------------------------------------------------------------
 47→
 48→function namespaceToBytes(namespaceUuid: string): Buffer {
 49→  const hex = namespaceUuid.replace(/-/g, "");
 50→  return Buffer.from(hex, "hex");
 51→}
 52→
 53→function generateUuidV5(namespace: string, name: string): string {
 54→  const namespaceBytes = namespaceToBytes(namespace);
 55→  const nameBytes = Buffer.from(name, "utf-8");
 56→
 57→  const hashInput = Buffer.concat([namespaceBytes, nameBytes]);
 58→  const hash = createHash("sha1").update(hashInput).digest();
 59→
 60→  // Set version to 5 (bits 4-7 of byte 6)
 61→  hash[6] = (hash[6] & 0x0f) | 0x50;
 62→
 63→  // Set variant to RFC 4122 (bits 6-7 of byte 8)
 64→  hash[8] = (hash[8] & 0x3f) | 0x80;
 65→
 66→  // Format as UUID string (use first 16 bytes of SHA-1)
 67→  const hex = hash.subarray(0, 16).toString("hex");
 68→  return [
 69→    hex.slice(0, 8),
 70→    hex.slice(8, 12),
 71→    hex.slice(12, 16),
 72→    hex.slice(16, 20),
 73→    hex.slice(20, 32),
 74→  ].join("-");
 75→}
 76→
 77→// ---------------------------------------------------------------------------
 78→// Title Truncation
 79→// ---------------------------------------------------------------------------
 80→
 81→export function truncateTitle(text: string, maxLength: number = MAX_TITLE_LENGTH): string {
 82→  if (text.length <= maxLength) return text;
 83→  return text.slice(0, maxLength) + "...";
 84→}
 85→
 86→// ---------------------------------------------------------------------------
 87→// System Prompt Normalization
 88→// ---------------------------------------------------------------------------
 89→
 90→function normalizeSystemPrompt(input: SessionHashInput): string | undefined {
 91→  if (input.systemPrompt) return input.systemPrompt;
 92→
 93→  if (input.systemPromptBlocks && input.systemPromptBlocks.length > 0) {
 94→    const textBlocks = input.systemPromptBlocks
 95→      .filter((block) => block.type === "text")
 96→      .map((block) => block.text);
 97→    return textBlocks.length > 0 ? textBlocks.join("\n") : undefined;
 98→  }
 99→
100→  return undefined;
101→}
102→
103→// ---------------------------------------------------------------------------
104→// First User Message Extraction
105→// ---------------------------------------------------------------------------
106→
107→function extractFirstUserMessage(
108→  messages: ReadonlyArray<{ role: string; content: string }>,
109→): string | undefined {
110→  const firstUserMsg = messages.find((msg) => msg.role === "user");
111→  return firstUserMsg?.content;
112→}
113→
114→// ---------------------------------------------------------------------------
115→// Public API
116→// ---------------------------------------------------------------------------
117→
118→/**
119→ * Resolve a deterministic session identity from request content.
120→ *
121→ * Returns undefined when either the system prompt or the first user message
122→ * is missing -- these are required to compute a stable hash.
123→ *
124→ * The session ID is a UUIDv5 derived from:
125→ *   UUIDv5(BRAIN_PROXY_NAMESPACE, system_prompt + NUL + first_user_message)
126→ *
127→ * The title is the first user message, truncated to ~100 characters.
128→ */
129→export function resolveSessionHash(
130→  input: SessionHashInput,
131→): SessionHashResult | undefined {
132→  const systemPrompt = normalizeSystemPrompt(input);
133→  if (!systemPrompt) return undefined;
134→
135→  const firstUserMessage = extractFirstUserMessage(input.messages);
136→  if (!firstUserMessage) return undefined;
137→
138→  const hashContent = systemPrompt + NUL_SEPARATOR + firstUserMessage;
139→  const sessionId = generateUuidV5(BRAIN_PROXY_NAMESPACE, hashContent);
140→  const title = truncateTitle(firstUserMessage);
141→
142→  return { sessionId, title };
143→}
144→

  1→/**
  2→ * Event bridge: transforms Claude Agent SDK messages into Brain StreamEvent
  3→ * variants and forwards them to the SSE registry.
  4→ *
  5→ * Pure transform function (transformSdkMessage) + effectful bridge handle
  6→ * (startEventBridge) that manages the event forwarding lifecycle.
  7→ */
  8→import type {
  9→  AgentTokenEvent,
 10→  AgentFileChangeEvent,
 11→  AgentStatusEvent,
 12→  StreamEvent,
 13→} from "../../shared/contracts";
 14→import type { StallDetectorHandle } from "./stall-detector";
 15→import { log } from "../telemetry/logger";
 16→
 17→// ---------------------------------------------------------------------------
 18→// SDK message types (from @anthropic-ai/claude-code)
 19→// ---------------------------------------------------------------------------
 20→
 21→export type ContentBlock =
 22→  | { type: "text"; text: string }
 23→  | { type: "tool_use"; id: string; name: string; input: Record<string, unknown> }
 24→  | { type: "tool_result"; tool_use_id: string; content: string };
 25→
 26→export type SdkMessage =
 27→  | { type: "assistant"; content: ContentBlock[] }
 28→  | { type: "result"; subtype: "success"; duration_ms: number }
 29→  | { type: "result"; subtype: "error"; error: string }
 30→  | { type: "system"; subtype: string; [key: string]: unknown }
 31→  | { type: "user" };
 32→
 33→// ---------------------------------------------------------------------------
 34→// Port: dependencies as function signatures
 35→// ---------------------------------------------------------------------------
 36→
 37→export type EventBridgeDeps = {
 38→  emitEvent: (streamId: string, event: StreamEvent) => void;
 39→  updateLastEventAt: (sessionId: string) => Promise<void>;
 40→};
 41→
 42→// ---------------------------------------------------------------------------
 43→// Bridge handle
 44→// ---------------------------------------------------------------------------
 45→
 46→export type EventBridgeHandle = {
 47→  handleMessage: (message: SdkMessage) => void;
 48→  stop: () => void;
 49→};
 50→
 51→// ---------------------------------------------------------------------------
 52→// File operation tool detection
 53→// ---------------------------------------------------------------------------
 54→
 55→/** Tool names that represent file write/edit operations. */
 56→const FILE_WRITE_TOOLS = new Set(["Write"]);
 57→const FILE_EDIT_TOOLS = new Set(["Edit"]);
 58→
 59→function isFileOperationTool(toolName: string): boolean {
 60→  return FILE_WRITE_TOOLS.has(toolName) || FILE_EDIT_TOOLS.has(toolName);
 61→}
 62→
 63→function extractFileChangeType(toolName: string): AgentFileChangeEvent["changeType"] {
 64→  if (FILE_WRITE_TOOLS.has(toolName)) return "created";
 65→  if (FILE_EDIT_TOOLS.has(toolName)) return "modified";
 66→  return "modified";
 67→}
 68→
 69→function extractFilePath(input: Record<string, unknown>): string | undefined {
 70→  if (typeof input.file_path === "string") return input.file_path;
 71→  return undefined;
 72→}
 73→
 74→// ---------------------------------------------------------------------------
 75→// Pure transform: SDK message -> Brain StreamEvent[]
 76→// ---------------------------------------------------------------------------
 77→
 78→function transformTextBlock(
 79→  block: { type: "text"; text: string },
 80→  sessionId: string,
 81→): AgentTokenEvent {
 82→  return {
 83→    type: "agent_token",
 84→    sessionId,
 85→    token: block.text,
 86→  };
 87→}
 88→
 89→function transformToolUseBlock(
 90→  block: { type: "tool_use"; id: string; name: string; input: Record<string, unknown> },
 91→  sessionId: string,
 92→): AgentFileChangeEvent | undefined {
 93→  if (!isFileOperationTool(block.name)) return undefined;
 94→
 95→  const filePath = extractFilePath(block.input);
 96→  if (!filePath) return undefined;
 97→
 98→  return {
 99→    type: "agent_file_change",
100→    sessionId,
101→    file: filePath,
102→    changeType: extractFileChangeType(block.name),
103→  };
104→}
105→
106→function transformAssistantContent(
107→  content: ContentBlock[],
108→  sessionId: string,
109→): StreamEvent[] {
110→  const events: StreamEvent[] = [];
111→  for (const block of content) {
112→    if (block.type === "text") {
113→      events.push(transformTextBlock(block, sessionId));
114→    } else if (block.type === "tool_use") {
115→      const fileEvent = transformToolUseBlock(block, sessionId);
116→      if (fileEvent) events.push(fileEvent);
117→    }
118→  }
119→  return events;
120→}
121→
122→function transformResultMessage(
123→  message: { type: "result"; subtype: "success"; duration_ms: number } | { type: "result"; subtype: "error"; error: string },
124→  sessionId: string,
125→): AgentStatusEvent {
126→  if (message.subtype === "error") {
127→    return {
128→      type: "agent_status",
129→      sessionId,
130→      status: "error",
131→      error: message.error,
132→    };
133→  }
134→  return {
135→    type: "agent_status",
136→    sessionId,
137→    status: "completed",
138→  };
139→}
140→
141→function transformSystemMessage(
142→  message: { type: "system"; subtype: string; [key: string]: unknown },
143→  sessionId: string,
144→): AgentTokenEvent | undefined {
145→  const subtype = message.subtype;
146→
147→  if (subtype === "init") {
148→    const version = message.claude_code_version ?? "unknown";
149→    return { type: "agent_token", sessionId, token: `[system] Claude Code ${version} initialized\n` };
150→  }
151→
152→  if (subtype === "mcp_server_error") {
153→    const server = (message as Record<string, unknown>).server_name ?? "unknown";
154→    const error = (message as Record<string, unknown>).error ?? "";
155→    return { type: "agent_token", sessionId, token: `[system] MCP server "${server}" failed: ${error}\n` };
156→  }
157→
158→  // Surface other system subtypes as informational tokens
159→  return { type: "agent_token", sessionId, token: `[system] ${subtype}\n` };
160→}
161→
162→export function transformSdkMessage(
163→  message: SdkMessage,
164→  sessionId: string,
165→): StreamEvent[] {
166→  switch (message.type) {
167→    case "assistant":
168→      return transformAssistantContent(message.content, sessionId);
169→
170→    case "result":
171→      return [transformResultMessage(message, sessionId)];
172→
173→    case "system": {
174→      const event = transformSystemMessage(message, sessionId);
175→      return event ? [event] : [];
176→    }
177→
178→    default:
179→      return [];
180→  }
181→}
182→
183→// ---------------------------------------------------------------------------
184→// Step event detection for stall detector
185→// ---------------------------------------------------------------------------
186→
187→/** Returns true if the message contains tool_use blocks for file operations. */
188→function containsFileOperationStep(message: SdkMessage): boolean {
189→  if (message.type !== "assistant") return false;
190→  return message.content.some(
191→    (block) => block.type === "tool_use" && isFileOperationTool(block.name),
192→  );
193→}
194→
195→// ---------------------------------------------------------------------------
196→// Bridge handle factory
197→// ---------------------------------------------------------------------------
198→
199→export function startEventBridge(
200→  deps: EventBridgeDeps,
201→  streamId: string,
202→  sessionId: string,
203→  stallDetector?: StallDetectorHandle,
204→): EventBridgeHandle {
205→  let stopped = false;
206→
207→  const handleMessage = (message: SdkMessage): void => {
208→    if (stopped) return;
209→
210→    const streamEvents = transformSdkMessage(message, sessionId);
211→    for (const streamEvent of streamEvents) {
212→      deps.emitEvent(streamId, streamEvent);
213→    }
214→
215→    // Fire-and-forget: update last_event_at for stall detection
216→    if (streamEvents.length > 0) {
217→      deps.updateLastEventAt(sessionId).catch((err) => {
218→        log.warn("event-bridge", "Failed to update last_event_at", { sessionId, error: String(err) });
219→      });
220→    }
221→
222→    // Notify stall detector of activity
223→    if (stallDetector && streamEvents.length > 0) {
224→      stallDetector.recordActivity();
225→
226→      if (containsFileOperationStep(message)) {
227→        stallDetector.incrementStepCount();
228→      }
229→    }
230→  };
231→
232→  return {
233→    handleMessage,
234→    stop(): void {
235→      stopped = true;
236→      stallDetector?.stop();
237→    },
238→  };
239→}
