 43→export function createFeedRouteHandler(
 44→  deps: ServerDependencies,
 45→): (workspaceId: string) => Promise<Response> {
 46→  return (workspaceId: string) => handleFeed(deps, workspaceId);
 47→}
 48→
 49→async function handleFeed(deps: ServerDependencies, workspaceId: string): Promise<Response> {
 50→  const startedAt = performance.now();
 51→  log.info("feed.started", "Governance feed request started", { workspaceId });
 52→
 53→  let workspaceRecord: RecordId<"workspace", string>;
 54→  try {
 55→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 56→  } catch (error) {
 57→    if (error instanceof HttpError) {
 58→      log.warn("feed.workspace_resolve.http_error", "Feed workspace resolve failed", {
 59→        workspaceId,
 60→        statusCode: error.status,
 61→      });
 62→      return jsonError(error.message, error.status);
 63→    }
 64→    log.error("feed.workspace_resolve.failed", "Feed workspace resolve failed", error, { workspaceId });
 65→    return jsonError("failed to resolve workspace", 500);
 66→  }
 67→
 68→  try {
 69→    const queryInput = { surreal: deps.surreal, workspaceRecord, limit: FEED_ITEM_LIMIT };
 70→
 71→    const [
 72→      provisionalDecisions,
 73→      conflicts,
 74→      blockingQuestions,
 75→      lowConfidenceDecisions,
 76→      blockedTasks,
 77→      observations,
 78→      suggestions,
 79→      staleTasks,
 80→      recentlyCompleted,
 81→      recentExtractions,
 82→      agentAttentionSessions,
 83→      pendingVetoIntents,
 84→      recentlyVetoedIntents,
 85→      pendingLearnings,
 86→    ] = await Promise.all([
 87→      listProvisionalDecisions(queryInput),
 88→      listWorkspaceConflicts(queryInput),
 89→      listBlockingQuestions(queryInput),
 90→      listLowConfidenceDecisions({ ...queryInput, confidenceThreshold: LOW_CONFIDENCE_THRESHOLD }),
 91→      listBlockedTasks(queryInput),
 92→      listWorkspaceOpenObservations({ surreal: deps.surreal, workspaceRecord, limit: FEED_ITEM_LIMIT }),
 93→      listWorkspacePendingSuggestions({ surreal: deps.surreal, workspaceRecord, limit: FEED_ITEM_LIMIT }),
 94→      listStaleTasks({ ...queryInput, staleDays: STALE_DAYS }),
 95→      listRecentlyCompletedItems({ ...queryInput, recentDays: RECENT_COMPLETED_DAYS }),
 96→      listRecentExtractions({ ...queryInput, cutoff: new Date(Date.now() - AWARENESS_RECENCY_DAYS * 24 * 60 * 60 * 1000) }),
 97→      listAgentAttentionSessions(queryInput),
 98→      listPendingVetoIntents(queryInput),
 99→      listRecentlyVetoedIntents(queryInput),
100→      listWorkspacePendingLearnings({ surreal: deps.surreal, workspaceRecord, limit: FEED_ITEM_LIMIT }),
101→    ]);
102→
103→    const blocking: GovernanceFeedItem[] = [];
104→    const review: GovernanceFeedItem[] = [];
105→    const awareness: GovernanceFeedItem[] = [];
106→
107→    // Blocking: provisional decisions
108→    for (const row of provisionalDecisions) {
109→      const rawId = row.id.id as string;
110→      blocking.push({
111→        id: `decision:${rawId}:${row.status}`,
112→        tier: "blocking",
113→        entityId: `decision:${rawId}`,
114→        entityKind: "decision",
115→        entityName: row.summary,
116→        reason: `${capitalize(row.status)} decision awaiting confirmation`,
117→        status: row.status,
118→        ...(row.project ? { project: row.project } : {}),
119→        ...(row.category ? { category: row.category as EntityCategory } : {}),
120→        ...(row.priority ? { priority: row.priority as EntityPriority } : {}),
121→        createdAt: toIsoString(row.created_at),
122→        actions: decisionActions(),
123→      });
124→    }
125→
126→    // Blocking: conflicts
127→    for (const row of conflicts) {
128→      blocking.push({
129→        id: `conflict:${row.edgeId}`,
130→        tier: "blocking",
131→        entityId: `${row.fromKind}:${row.fromRecord.id as string}`,
132→        entityKind: row.fromKind as EntityKind,
133→        entityName: row.fromName,
134→        reason: row.description ?? `Conflicts with ${row.toName}`,
135→        status: "conflict",
136→        ...(row.severity ? { severity: row.severity as ObservationSeverity } : {}),
137→        createdAt: row.detectedAt,
138→        actions: conflictActions(),
139→        conflictTarget: {
140→          entityId: `${row.toKind}:${row.toRecord.id as string}`,
141→          entityKind: row.toKind as EntityKind,
142→          entityName: row.toName,
143→        },
144→      });
145→    }
146→
147→    // Blocking: high/critical questions
148→    for (const row of blockingQuestions) {
149→      const rawId = row.id.id as string;
150→      blocking.push({
151→        id: `question:${rawId}:blocking`,
152→        tier: "blocking",
153→        entityId: `question:${rawId}`,
154→        entityKind: "question",
155→        entityName: row.text,
156→        reason: `${capitalize(row.priority)} priority open question`,
157→        status: row.status,
158→        ...(row.project ? { project: row.project } : {}),
159→        ...(row.category ? { category: row.category as EntityCategory } : {}),
160→        priority: row.priority as EntityPriority,
161→        createdAt: toIsoString(row.created_at),
162→        actions: questionActions(),
163→      });
164→    }
165→
166→    // Blocking + Review: agent attention sessions (error -> blocking, idle -> review)
167→    for (const session of agentAttentionSessions) {
168→      const item = mapAgentSessionToFeedItem(session);
169→      if (item.tier === "blocking") {
170→        blocking.push(item);
171→      } else {
172→        review.push(item);
173→      }
174→    }
175→
176→    // Blocking: pending veto intents (agent actions awaiting human review)
177→    for (const intent of pendingVetoIntents) {
178→      blocking.push(mapPendingIntentToFeedItem(intent));
179→    }
180→
181→    // Review: low confidence decisions
182→    for (const row of lowConfidenceDecisions) {
183→      const rawId = row.id.id as string;
184→      review.push({
185→        id: `decision:${rawId}:low_confidence`,
186→        tier: "review",
187→        entityId: `decision:${rawId}`,
188→        entityKind: "decision",
189→        entityName: row.summary,
190→        reason: `Low confidence inferred decision (${Math.round(row.extraction_confidence * 100)}%)`,
191→        status: row.status,
192→        ...(row.project ? { project: row.project } : {}),
193→        ...(row.category ? { category: row.category as EntityCategory } : {}),
194→        ...(row.priority ? { priority: row.priority as EntityPriority } : {}),
195→        createdAt: toIsoString(row.created_at),
196→        actions: decisionActions(),
197→      });
198→    }
199→
200→    // Review: blocked tasks
201→    for (const row of blockedTasks) {
202→      const rawId = row.id.id as string;
203→      review.push({
204→        id: `task:${rawId}:blocked`,
205→        tier: "review",
206→        entityId: `task:${rawId}`,
207→        entityKind: "task",
208→        entityName: row.title,
209→        reason: "Task is blocked",
210→        status: row.status,
211→        ...(row.project ? { project: row.project } : {}),
212→        ...(row.category ? { category: row.category as EntityCategory } : {}),
213→        ...(row.priority ? { priority: row.priority as EntityPriority } : {}),
214→        createdAt: toIsoString(row.created_at),
215→        actions: blockedTaskActions(),
216→      });
217→    }
218→
219→    // Review: all open/acknowledged observations need human action
220→    for (const obs of observations) {
221→      review.push({
222→        id: `observation:${obs.id}:${obs.severity}`,
223→        tier: "review",
224→        entityId: `observation:${obs.id}`,
225→        entityKind: "observation",
226→        entityName: obs.text,
227→        reason: `${capitalize(obs.severity)} observation from ${obs.sourceAgent}`,
228→        status: obs.status,
229→        ...(obs.category ? { category: obs.category } : {}),
230→        severity: obs.severity,
231→        createdAt: obs.createdAt,
232→        actions: observationActions(obs.status),
233→      });
234→    }
235→
236→    // Review: pending suggestions from agents
237→    for (const sug of suggestions) {
238→      review.push({
239→        id: `suggestion:${sug.id}:${sug.category}`,
240→        tier: "review",
241→        entityId: `suggestion:${sug.id}`,
242→        entityKind: "suggestion",
243→        entityName: sug.text,
244→        reason: `${capitalize(sug.category)} suggestion from ${sug.suggestedBy} (confidence ${Math.round(sug.confidence * 100)}%)`,
245→        status: sug.status,
246→        createdAt: sug.createdAt,
247→        actions: suggestionActions(),
248→      });
249→    }
250→
251→    // Review: pending learnings awaiting human approval
252→    for (const learning of pendingLearnings) {
253→      const confidence = learning.patternConfidence !== undefined
254→        ? ` (confidence ${Math.round(learning.patternConfidence * 100)}%)`
255→        : "";
256→      review.push({
257→        id: `learning:${learning.id}:pending_approval`,
258→        tier: "review",
259→        entityId: `learning:${learning.id}`,
260→        entityKind: "learning",
261→        entityName: learning.text,
262→        reason: `Pending learning from ${learning.suggestedBy ?? learning.source}${confidence}`,
263→        status: "pending_approval",
264→        createdAt: learning.createdAt,
265→        actions: learningActions(),
266→      });
267→    }
268→
269→    // Awareness items are filtered to the last AWARENESS_RECENCY_DAYS
270→    const awarenessCutoff = new Date(Date.now() - AWARENESS_RECENCY_DAYS * 24 * 60 * 60 * 1000);
271→
272→    // Awareness: stale tasks (only if they crossed the stale threshold recently)
273→    for (const row of staleTasks) {
274→      const ts = row.updated_at ? new Date(row.updated_at) : new Date(row.created_at);
275→      if (ts < awarenessCutoff) continue;
276→      const rawId = row.id.id as string;
277→      awareness.push({
278→        id: `task:${rawId}:stale`,
279→        tier: "awareness",
280→        entityId: `task:${rawId}`,
281→        entityKind: "task",
282→        entityName: row.title,
283→        reason: `Task open for over ${STALE_DAYS} days`,
284→        status: row.status,
285→        ...(row.project ? { project: row.project } : {}),
286→        ...(row.category ? { category: row.category as EntityCategory } : {}),
287→        ...(row.priority ? { priority: row.priority as EntityPriority } : {}),
288→        createdAt: toIsoString(row.created_at),
289→        actions: staleTaskActions(),
290→      });
291→    }
292→
293→    // Awareness: recently completed (already filtered by RECENT_COMPLETED_DAYS query)
294→    for (const row of recentlyCompleted) {
295→      const rawId = row.id.id as string;
296→      awareness.push({
297→        id: `${row.kind}:${rawId}:completed`,
298→        tier: "awareness",
299→        entityId: `${row.kind}:${rawId}`,
300→        entityKind: row.kind as EntityKind,
301→        entityName: row.name,
302→        reason: `Recently completed ${row.kind}`,
303→        status: row.status,
304→        ...(row.project ? { project: row.project } : {}),
305→        ...(row.category ? { category: row.category as EntityCategory } : {}),
306→        createdAt: toIsoString(row.updated_at),
307→        actions: [],
308→      });
309→    }
310→
311→    // Awareness: recently vetoed intents (dedup against blocking tier pending_veto intents)
312→    const blockingEntityIds = new Set<string>(blocking.map((item) => item.entityId));
313→    for (const row of recentlyVetoedIntents) {
314→      const entityId = `intent:${row.id.id as string}`;
315→      if (blockingEntityIds.has(entityId)) continue;
316→      awareness.push(mapVetoedIntentToFeedItem(row));
317→    }
318→
319→    // Awareness: recent extractions (skip entities already in higher tiers)
320→    const seenEntityIds = new Set<string>();
321→    for (const item of [...blocking, ...review, ...awareness]) {
322→      seenEntityIds.add(item.entityId);
323→    }
324→    for (const row of recentExtractions) {
325→      const entityId = `${row.entityKind}:${row.entityId}`;
326→      if (seenEntityIds.has(entityId)) continue;
327→      awareness.push({
328→        id: `extraction:${row.edgeId}`,
329→        tier: "awareness",
330→        entityId,
331→        entityKind: row.entityKind as EntityKind,
332→        entityName: row.entityName,
333→        reason: `Extracted from ${row.sourceKind.replace("_", " ")}`,
334→        status: "extracted",
335→        createdAt: row.extractedAt,
336→        actions: row.entityKind === "question" ? questionActions() : [],
337→      });
338→    }
339→
340→    const payload: GovernanceFeedResponse = {
341→      blocking,
342→      review,
343→      awareness,
344→      updatedAt: new Date().toISOString(),
345→    };
346→
347→    log.info("feed.completed", "Governance feed request completed", {
348→      workspaceId,
349→      blockingCount: blocking.length,
350→      reviewCount: review.length,
351→      awarenessCount: awareness.length,
352→      durationMs: elapsedMs(startedAt),
353→    });
354→
355→    return jsonResponse(payload, 200);
356→  } catch (error) {
357→    log.error("feed.failed", "Governance feed request failed", error, { workspaceId });
358→    const message = error instanceof Error ? error.message : "feed request failed";
359→    return jsonError(message, 500);
360→  }
361→}
