  1→/**
  2→ * Observer HTTP route: POST /api/observe/:table/:id
  3→ *
  4→ * Thin HTTP adapter. Parses request, resolves workspace, delegates to
  5→ * the observer agent for all verification logic (deterministic + LLM).
  6→ */
  7→
  8→import { RecordId, type Surreal } from "surrealdb";
  9→import type { LanguageModel } from "ai";
 10→import { jsonResponse } from "../http/response";
 11→import type { ServerDependencies } from "../runtime/types";
 12→import { runObserverAgent } from "../agents/observer/agent";
 13→import { runGraphScan } from "./graph-scan";
 14→import { analyzeTraceResponse } from "./trace-response-analyzer";
 15→import { analyzeSessionTraces } from "./session-trace-analyzer";
