 19→// Types
 20→// ---------------------------------------------------------------------------
 21→
 22→const SUPPORTED_TABLES = new Set<string>([
 23→  "task",
 24→  "intent",
 25→  "git_commit",
 26→  "decision",
 27→  "observation",
 28→  "trace",
 29→  "agent_session",
 30→]);
