 36→export function createObserverRouteHandler(deps: ServerDependencies) {
 37→  return async (table: string, id: string, request: Request): Promise<Response> => {
 38→    if (!SUPPORTED_TABLES.has(table)) {
 39→      return jsonResponse({ error: "unsupported_table", table }, 400);
 40→    }
 41→
 42→    try {
 43→      const body = await request.json().catch(() => undefined);
 44→
 45→      log.info("observer.event.received", "Observer event received", { table, id });
 46→
 47→      // Resolve workspace
 48→      const workspaceId = await resolveWorkspaceId(deps.surreal, table, id, body);
 49→      if (!workspaceId) {
 50→        log.error("observer.event.no_workspace", "Cannot determine workspace", { table, id });
 51→        return jsonResponse({ status: "ok" }, 200);
 52→      }
 53→
 54→      const workspaceRecord = new RecordId("workspace", workspaceId);
 55→
 56→      // Session-end analysis: cross-trace pattern detection
 57→      if (table === "agent_session") {
 58→        const sessionResult = await analyzeSessionTraces({
 59→          surreal: deps.surreal,
 60→          workspaceRecord,
 61→          sessionId: id,
 62→          observerModel: deps.observerModel as LanguageModel,
 63→        });
 64→
 65→        log.info("observer.session.verified", "Session trace analysis complete", {
 66→          sessionId: id,
 67→          observationsCreated: sessionResult.observations_created,
 68→          skipped: sessionResult.skipped,
 69→          reason: sessionResult.reason,
 70→          tracesAnalyzed: sessionResult.traces_analyzed,
 71→        });
 72→
 73→        return jsonResponse({ status: "ok" }, 200);
 74→      }
 75→
 76→      // Trace analysis uses a specialized pipeline (embedding + KNN + LLM verification)
 77→      if (table === "trace") {
 78→        const traceResult = await analyzeTraceResponse({
 79→          surreal: deps.surreal,
 80→          workspaceRecord,
 81→          traceId: id,
 82→          traceBody: body,
 83→          observerModel: deps.observerModel as LanguageModel,
 84→          embeddingModel: deps.embeddingModel,
 85→          embeddingDimension: deps.config.embeddingDimension,
 86→        });
 87→
 88→        log.info("observer.trace.verified", "Trace analysis complete", {
 89→          traceId: id,
 90→          observationsCreated: traceResult.observations_created,
 91→          skipped: traceResult.skipped,
 92→          reason: traceResult.reason,
 93→        });
 94→
 95→        return jsonResponse({ status: "ok" }, 200);
 96→      }
 97→
 98→      // Delegate to observer agent for all other entity types
 99→      const agentOutput = await runObserverAgent({
100→        surreal: deps.surreal,
101→        workspaceRecord,
102→        entityTable: table,
103→        entityId: id,
104→        entityBody: body,
105→        observerModel: deps.observerModel as LanguageModel,
106→      });
107→
108→      log.info(`observer.${table}.verified`, `${table} verification complete`, {
109→        [`${table}Id`]: id,
110→        verdict: agentOutput.verdict,
111→        observationsCreated: agentOutput.observations_created,
112→        evidence: agentOutput.evidence,
113→      });
114→
115→      return jsonResponse({ status: "ok" }, 200);
116→    } catch (error) {
117→      log.error("observer.event.error", "Observer event processing failed", error);
118→      // Return 200 to prevent SurrealDB EVENT retries for non-transient errors
119→      return jsonResponse({ status: "error", message: "processing failed" }, 200);
120→    }
121→  };
122→}
