150→// ---------------------------------------------------------------------------
151→// Workspace resolution
152→// ---------------------------------------------------------------------------
153→
154→// Workspace IDs may be UUIDs or prefixed slugs (e.g. test workspaces).
155→// Validate they contain only safe characters.
156→const WORKSPACE_ID_PATTERN = /^[a-zA-Z0-9_-]+$/;
157→
158→async function resolveWorkspaceId(
159→  surreal: Surreal,
160→  table: string,
161→  id: string,
162→  body?: Record<string, unknown>,
163→): Promise<string | undefined> {
164→  let wsId: string | undefined;
165→
166→  if (body?.workspace) {
167→    const ws = body.workspace;
168→    if (typeof ws === "string") {
169→      const cleaned = ws.replace(/`/g, "");
170→      wsId = cleaned.includes(":") ? cleaned.split(":")[1] : cleaned;
171→    } else if (typeof ws === "object" && ws !== null) {
172→      const wsObj = ws as { id?: string | { String?: string } };
173→      if (typeof wsObj.id === "string") wsId = wsObj.id.replace(/`/g, "");
174→      else if (wsObj.id && typeof (wsObj.id as { String?: string }).String === "string") {
175→        wsId = (wsObj.id as { String: string }).String.replace(/`/g, "");
176→      }
177→    }
178→  }
179→
180→  // Fallback: query the DB
181→  if (!wsId) {
182→    const record = new RecordId(table, id);
183→    const [rows] = await surreal.query<
184→      [Array<{ workspace: RecordId<"workspace", string> }>]
185→    >(
186→      `SELECT workspace FROM $record;`,
187→      { record },
188→    );
189→    wsId = rows?.[0]?.workspace ? (rows[0].workspace.id as string) : undefined;
190→  }
191→
192→  if (wsId && !WORKSPACE_ID_PATTERN.test(wsId)) {
193→    throw new Error(`Invalid workspace ID format: ${wsId}`);
194→  }
195→
196→  return wsId;
197→}
