  1→/**
  2→ * Proxy Token Route — POST /api/auth/proxy-token
  3→ *
  4→ * Issues brp_-prefixed proxy tokens for CLI authentication.
  5→ * Pipeline:
  6→ *   1. Parse workspace_id from request body + extract bearer token
  7→ *   2. Validate bearer token via Better Auth session
  8→ *   3. Resolve authenticated person → identity (scoped to workspace membership)
  9→ *   4. Revoke previous tokens + issue new one (atomic transaction)
 10→ *   5. Return raw token + expiry
 11→ *
 12→ * Driving port: POST /api/auth/proxy-token
 13→ * Driven ports: SurrealDB (proxy_token table)
 14→ */
 15→import { RecordId } from "surrealdb";
 16→import { jsonResponse } from "../http/response";
 17→import {
 18→  generateProxyToken,
 19→  hashProxyToken,
 20→  computeExpiresAt,
 21→  readProxyTokenTtlDays,
 22→} from "./proxy-token-core";
 23→import type { ServerDependencies } from "../runtime/types";
 24→import { log } from "../telemetry/logger";
 25→
 26→// ---------------------------------------------------------------------------
 27→// Request Parsing (pure)
 28→// ---------------------------------------------------------------------------
 29→
 30→type ProxyTokenRequest = {
 31→  workspaceId: string;
 32→  bearerToken: string;
 33→};
 34→
 35→function parseProxyTokenRequest(
 36→  authHeader: string | null,
 37→  body: unknown,
 38→): { ok: true; value: ProxyTokenRequest } | { ok: false; status: number; error: string } {
 39→  if (!authHeader || !authHeader.startsWith("Bearer ")) {
 40→    return { ok: false, status: 401, error: "missing_authorization" };
 41→  }
 42→
 43→  const bearerToken = authHeader.slice(7).trim();
 44→  if (!bearerToken) {
 45→    return { ok: false, status: 401, error: "missing_authorization" };
 46→  }
 47→
 48→  const parsed = body as { workspace_id?: string } | undefined;
 49→  if (!parsed?.workspace_id || typeof parsed.workspace_id !== "string") {
 50→    return { ok: false, status: 400, error: "workspace_id_required" };
 51→  }
 52→
 53→  return {
 54→    ok: true,
 55→    value: { workspaceId: parsed.workspace_id, bearerToken },
 56→  };
 57→}
 58→
 59→// ---------------------------------------------------------------------------
 60→// Identity Resolution (driven port — queries SurrealDB)
 61→// Resolves the identity for a person that is a member of the target workspace,
 62→// avoiding false 403s when a person has multiple identities.
 63→// ---------------------------------------------------------------------------
 64→
 65→async function resolveIdentityForWorkspaceAndPerson(
 66→  surreal: ServerDependencies["surreal"],
 67→  personId: string,
 68→  workspaceId: string,
 69→): Promise<string | undefined> {
 70→  const personRecord = new RecordId("person", personId);
 71→  const wsRecord = new RecordId("workspace", workspaceId);
 72→  const results = await surreal.query<[undefined, RecordId[]]>(
 73→    `LET $identities = SELECT VALUE in FROM identity_person WHERE out = $person;
 74→     SELECT VALUE id FROM identity WHERE id IN $identities AND id IN (SELECT VALUE in FROM member_of WHERE out = $ws) LIMIT 1;`,
 75→    { person: personRecord, ws: wsRecord },
 76→  );
 77→  const identityRec = results[1]?.[0];
 78→  return identityRec?.id as string | undefined;
 79→}
 80→
 81→// ---------------------------------------------------------------------------
 82→// Record ID Helpers
 83→// ---------------------------------------------------------------------------
 84→
 85→function identityRecord(identityId: string): RecordId {
 86→  return new RecordId("identity", identityId);
 87→}
 88→
 89→function workspaceRecord(workspaceId: string): RecordId {
 90→  return new RecordId("workspace", workspaceId);
 91→}
 92→
 93→// ---------------------------------------------------------------------------
 94→// Session Validation (driven port — Better Auth)
 95→// ---------------------------------------------------------------------------
 96→
 97→async function validateSession(
 98→  auth: ServerDependencies["auth"],
 99→  headers: Headers,
100→): Promise<string | undefined> {
101→  const session = await auth.api.getSession({ headers });
102→  return session?.user?.id;
103→}
104→
105→// ---------------------------------------------------------------------------
106→// Token Rotation (driven port — mutates SurrealDB)
107→// Revoke + issue in a single transaction to avoid a crash window where
108→// no valid token exists.
109→// ---------------------------------------------------------------------------
110→
111→async function rotateProxyToken(
112→  surreal: ServerDependencies["surreal"],
113→  tokenHash: string,
114→  identityId: string,
115→  workspaceId: string,
116→  expiresAt: Date,
117→): Promise<void> {
118→  await surreal.query(
119→    `BEGIN TRANSACTION;
120→     UPDATE proxy_token SET revoked = true WHERE identity = $identity AND workspace = $ws AND revoked = false;
121→     CREATE proxy_token CONTENT {
122→       token_hash: $hash,
123→       workspace: $ws,
124→       identity: $identity,
125→       expires_at: $expires,
126→       created_at: time::now(),
127→       revoked: false,
128→     };
129→     COMMIT TRANSACTION;`,
130→    {
131→      hash: tokenHash,
132→      ws: workspaceRecord(workspaceId),
133→      identity: identityRecord(identityId),
134→      expires: expiresAt,
135→    },
136→  );
137→}
138→
139→// ---------------------------------------------------------------------------
140→// Handler Factory
141→// ---------------------------------------------------------------------------
142→
143→export function createProxyTokenHandler(
144→  deps: ServerDependencies,
145→): (request: Request) => Promise<Response> {
146→  const ttlDays = readProxyTokenTtlDays();
147→
148→  return async (request: Request): Promise<Response> => {
149→    // 1. Parse request
150→    let body: unknown;
151→    try {
152→      body = await request.json();
153→    } catch {
154→      return jsonResponse({ error: "invalid_json" }, 400);
155→    }
156→
157→    const parseResult = parseProxyTokenRequest(
158→      request.headers.get("authorization"),
159→      body,
160→    );
161→
162→    if (!parseResult.ok) {
163→      return jsonResponse({ error: parseResult.error }, parseResult.status);
164→    }
165→
166→    const { workspaceId } = parseResult.value;
167→
168→    // 2. Validate bearer token via Better Auth session
169→    const personId = await validateSession(deps.auth, request.headers);
170→    if (!personId) {
171→      return jsonResponse({ error: "invalid_session" }, 401);
172→    }
173→
174→    // 3. Resolve person → identity (scoped to workspace membership)
175→    const identityId = await resolveIdentityForWorkspaceAndPerson(deps.surreal, personId, workspaceId);
176→    if (!identityId) {
177→      return jsonResponse({ error: "workspace_membership_required" }, 403);
178→    }
179→
180→    // 4. Revoke previous tokens + issue new one (atomic)
181→    const rawToken = generateProxyToken();
182→    const tokenHash = hashProxyToken(rawToken);
183→    const expiresAt = computeExpiresAt(ttlDays);
184→
185→    await rotateProxyToken(deps.surreal, tokenHash, identityId, workspaceId, expiresAt);
186→
187→    log.info("proxy.token.issued", "Proxy token issued", {
188→      workspace_id: workspaceId,
189→      identity_id: identityId,
190→      ttl_days: ttlDays,
191→    });
192→
193→    // 5. Return raw token (only time it leaves the server)
194→    return jsonResponse({
195→      proxy_token: rawToken,
196→      expires_at: expiresAt.toISOString(),
197→      workspace_id: workspaceId,
198→    }, 200);
199→  };
200→}
