 75→// ---------------------------------------------------------------------------
 76→// Workspace Validation (cached)
 77→// ---------------------------------------------------------------------------
 78→
 79→type WorkspaceCache = Map<string, { valid: boolean; checkedAt: number }>;
 80→
 81→const WORKSPACE_CACHE_TTL_MS = 60_000; // 1 minute
 82→
 83→async function validateWorkspace(
 84→  surreal: ServerDependencies["surreal"],
 85→  workspaceId: string,
 86→  cache: WorkspaceCache,
 87→): Promise<boolean> {
 88→  const cached = cache.get(workspaceId);
 89→  if (cached && Date.now() - cached.checkedAt < WORKSPACE_CACHE_TTL_MS) {
 90→    return cached.valid;
 91→  }
 92→
 93→  try {
 94→    const results = await surreal.query<[Array<{ id: RecordId }>]>(
 95→      `SELECT id FROM $ws;`,
 96→      { ws: new RecordId("workspace", workspaceId) },
 97→    );
 98→    const valid = (results[0]?.length ?? 0) > 0;
 99→    cache.set(workspaceId, { valid, checkedAt: Date.now() });
100→    return valid;
101→  } catch {
102→    cache.set(workspaceId, { valid: false, checkedAt: Date.now() });
103→    return false;
104→  }
105→}
