107→// ---------------------------------------------------------------------------
108→// Auth Mode (dual-mode: Brain auth vs direct auth)
109→// ---------------------------------------------------------------------------
110→
111→export type AuthMode =
112→  | { mode: "direct" }
113→  | { mode: "brain"; serverApiKey?: string };
114→
115→// ---------------------------------------------------------------------------
116→// Header Forwarding
117→// ---------------------------------------------------------------------------
118→
119→export function buildUpstreamHeaders(request: Request, authMode: AuthMode): Headers {
120→  const headers = new Headers();
121→
122→  for (const name of FORWARDED_HEADERS) {
123→    const value = request.headers.get(name);
124→    if (value) headers.set(name, value);
125→  }
126→
127→  if (authMode.mode === "brain" && authMode.serverApiKey) {
128→    // Brain auth with server-held API key: inject it, do not forward client auth
129→    headers.set("x-api-key", authMode.serverApiKey);
130→  } else {
131→    // Direct auth: forward client's auth headers as-is
132→    const xApiKey = request.headers.get("x-api-key");
133→    const authHeader = request.headers.get("authorization");
134→    if (xApiKey) headers.set("x-api-key", xApiKey);
135→    if (authHeader) headers.set("authorization", authHeader);
136→  }
137→
138→  return headers;
139→}
