170→// ---------------------------------------------------------------------------
171→// SSE Usage Extraction
172→// ---------------------------------------------------------------------------
173→
174→type StreamContext = {
175→  model?: string;
176→  inputTokens: number;
177→  outputTokens: number;
178→  cacheCreationTokens: number;
179→  cacheReadTokens: number;
180→  stopReason?: string;
181→};
182→
183→function extractSSEUsage(buffer: string, ctx: StreamContext): string {
184→  const lines = buffer.split("\n");
185→  const remainder = lines.pop() ?? "";
186→
187→  for (const line of lines) {
188→    if (!line.startsWith("data: ")) continue;
189→    const data = line.slice(6);
190→    if (data === "[DONE]") continue;
191→
192→    try {
193→      const event = JSON.parse(data);
194→
195→      if (event.type === "message_start" && event.message?.usage) {
196→        ctx.inputTokens = event.message.usage.input_tokens ?? 0;
197→        ctx.cacheCreationTokens = event.message.usage.cache_creation_input_tokens ?? 0;
198→        ctx.cacheReadTokens = event.message.usage.cache_read_input_tokens ?? 0;
199→        ctx.model = event.message.model ?? ctx.model;
200→      }
201→
202→      if (event.type === "message_delta") {
203→        if (event.usage?.output_tokens) {
204→          ctx.outputTokens = event.usage.output_tokens;
205→        }
206→        if (event.delta?.stop_reason) {
207→          ctx.stopReason = event.delta.stop_reason;
208→        }
209→      }
210→    } catch {
211→      // partial JSON or non-JSON data line — skip
212→    }
213→  }
214→
215→  return remainder;
216→}
217→
218→// ---------------------------------------------------------------------------
219→// Non-Streaming Usage Extraction
220→// ---------------------------------------------------------------------------
221→
222→type NonStreamingResponse = {
223→  model?: string;
224→  usage?: {
225→    input_tokens?: number;
226→    output_tokens?: number;
227→    cache_creation_input_tokens?: number;
228→    cache_read_input_tokens?: number;
229→  };
230→  stop_reason?: string;
231→};
232→
233→function extractNonStreamingUsage(
234→  responseBody: string,
235→  requestModel: string | undefined,
236→  latencyMs: number,
237→  identity: { workspaceId?: string; taskId?: string; identityId?: string },
238→  sessionId?: string,
239→  policyDecision?: PolicyDecisionLog,
240→  injectionResult?: InjectionResult,
241→): TraceData | undefined {
242→  try {
243→    const parsed = JSON.parse(responseBody) as NonStreamingResponse;
244→    if (!parsed.usage) return undefined;
245→
246→    const traceData: TraceData = {
247→      model: parsed.model ?? requestModel ?? "unknown",
248→      inputTokens: parsed.usage.input_tokens ?? 0,
249→      outputTokens: parsed.usage.output_tokens ?? 0,
250→      cacheCreationTokens: parsed.usage.cache_creation_input_tokens ?? 0,
251→      cacheReadTokens: parsed.usage.cache_read_input_tokens ?? 0,
252→      stopReason: parsed.stop_reason,
253→      latencyMs,
254→      workspaceId: identity.workspaceId,
255→      identityId: identity.identityId,
256→      sessionId,
257→      taskId: identity.taskId,
258→      policyDecision,
259→    };
260→
261→    // Add intelligence metadata if injection occurred
262→    if (injectionResult) {
263→      (traceData as any).intelligenceMetadata = buildIntelligenceMetadata(injectionResult);
264→    }
265→
266→    // Capture response content (opaque, per ADR-051)
267→    const responseContent = extractResponseContent(responseBody);
268→    if (responseContent) {
269→      (traceData as any).responseContent = responseContent;
270→    }
271→
272→    return traceData;
273→  } catch {
274→    return undefined;
275→  }
276→}
