567→// ---------------------------------------------------------------------------
568→// Handler Factory
569→// ---------------------------------------------------------------------------
570→
571→export function createAnthropicProxyHandler(
572→  deps: ServerDependencies,
573→): (request: Request) => Promise<Response> {
574→  const workspaceCache: WorkspaceCache = new Map();
575→  const rateLimiterState: RateLimiterState = createRateLimiterState();
576→  const spendCache: SpendCache = new Map();
577→  const noPolicyWarnedWorkspaces = new Set<string>();
578→  const contextCache: ContextCache = createContextCache(300); // default TTL, overridden per-workspace
579→
580→  // Proxy auth: per-handler cache + DB lookup function (not module-level singletons)
581→  const proxyTokenCache: TokenCache = createTokenCache();
582→  const lookupProxyToken: LookupProxyToken = createLookupProxyToken(deps.surreal);
583→
584→  // Periodic pruning of stale rate limiter entries to prevent unbounded Map growth.
585→  // unref() ensures this interval does not keep the process alive on shutdown.
586→  const pruneInterval = setInterval(
587→    () => {
588→      pruneStaleEntries(rateLimiterState, Date.now());
589→      const nowMs = Date.now();
590→      for (const [key, entry] of proxyTokenCache) {
591→        if (nowMs >= entry.expiresAt) proxyTokenCache.delete(key);
592→      }
593→    },
594→    5 * 60 * 1000,
595→  );
596→  pruneInterval.unref();
597→
598→  const anthropicApiUrl = deps.config.anthropicApiUrl;
599→
600→  return async (request: Request): Promise<Response> => {
601→    const startedAt = performance.now();
602→    const url = new URL(request.url);
603→    const upstreamPath = url.pathname.replace(/^\/proxy\/llm\/anthropic/, "");
604→    const upstreamUrl = `${anthropicApiUrl}${upstreamPath}`;
605→    const isCountTokens = isCountTokensRequest(url.pathname);
606→
607→    // --- Step 1: Parse request body (malformed body forwarded as-is) ---
608→    const body = await request.text();
609→    const parsed = tryParseRequestBody(body);
610→    const isStreaming = parsed?.stream === true;
611→
612→    // --- Step 1.5: Brain auth resolution (dual-mode) ---
613→    let brainAuthResult: ProxyAuthResult | undefined;
614→    let authMode: AuthMode = { mode: "direct" };
615→
616→    try {
617→      brainAuthResult = await resolveProxyAuth(
618→        request.headers,
619→        lookupProxyToken,
620→        proxyTokenCache,
621→      );
622→    } catch (error) {
623→      if (error instanceof ProxyAuthError) {
624→        return jsonResponse(
625→          { error: { type: "authentication_error", message: error.message } },
626→          401,
627→        );
628→      }
629→      throw error;
630→    }
631→
632→    if (brainAuthResult) {
633→      // Brain auth mode: use server API key if available, otherwise forward client auth headers
634→      authMode = { mode: "brain", serverApiKey: deps.config.anthropicApiKey };
635→    }
636→
637→    // --- Step 2: Identity resolution ---
638→    // In Brain auth mode, workspace comes from the token (not from headers)
639→    const identitySignals = resolveIdentity({
640→      metadataUserId: parsed?.metadata?.user_id,
641→      workspaceHeader: brainAuthResult?.workspaceId ?? (request.headers.get("X-Brain-Workspace") ?? undefined),
642→      taskHeader: request.headers.get("X-Brain-Task") ?? undefined,
643→      agentTypeHeader: request.headers.get("X-Brain-Agent-Type") ?? undefined,
644→      sessionHeader: request.headers.get("X-Brain-Session") ?? undefined,
645→      proxyTokenIdentityId: brainAuthResult?.identityId,
646→      userAgent: request.headers.get("User-Agent") ?? undefined,
647→    });
648→
649→    // --- Step 3: Session ID resolution ---
650→    // resolveSessionId returns either the header PK or the external Claude Code
651→    // session UUID. Resolve to the actual agent_session PK via DB lookup.
652→    const rawSessionId = resolveSessionId(identitySignals);
653→    let effectiveSessionId = rawSessionId
654→      ? await resolveAgentSessionId(deps.surreal, rawSessionId)
655→      : undefined;
656→
657→    // --- Step 3.5: Session hash fallback ---
658→    // When no explicit session signal exists, derive a deterministic session
659→    // identity from request content (system_prompt + first_user_message).
660→    if (!effectiveSessionId && identitySignals.workspaceId && parsed) {
661→      const sessionHashInput: SessionHashInput = {
662→        systemPrompt: typeof parsed.system === "string" ? parsed.system : undefined,
663→        systemPromptBlocks: Array.isArray(parsed.system) ? parsed.system : undefined,
664→        messages: parsed.messages ?? [],
665→      };
666→      const sessionHash = resolveSessionHash(sessionHashInput);
667→
668→      if (sessionHash) {
669→        try {
670→          const upsertedSessionId = await upsertProxySession(
671→            {
672→              sessionId: sessionHash.sessionId,
673→              workspaceId: identitySignals.workspaceId,
674→              agent: resolveAgentName(identitySignals),
675→            },
676→            { surreal: deps.surreal },
677→          );
678→          if (upsertedSessionId) {
679→            effectiveSessionId = upsertedSessionId;
680→          }
681→        } catch (error) {
682→          log.warn("proxy.anthropic.session_hash_upsert_failed", "Session hash upsert failed — continuing without session link", {
683→            error: String(error),
684→          });
685→        }
686→      }
687→    }
688→
689→    // --- Workspace validation (non-blocking) ---
690→    if (identitySignals.workspaceId) {
691→      const isValid = await validateWorkspace(
692→        deps.surreal,
693→        identitySignals.workspaceId,
694→        workspaceCache,
695→      );
696→      if (!isValid) {
697→        log.warn("proxy.anthropic.invalid_workspace", "Workspace not found in database", {
698→          workspaceId: identitySignals.workspaceId,
699→        });
700→      }
701→    }
702→
703→    // --- Step 4: Policy evaluation ---
704→    let policyResult: ProxyPolicyResult | undefined;
705→    if (parsed?.model && !isCountTokens) {
706→      const policyDeps: ProxyPolicyDependencies = {
707→        surreal: deps.surreal,
708→        inflight: deps.inflight,
709→        rateLimiterState,
710→        spendCache,
711→      };
712→
