16→  readonly id: string;
17→  readonly type: "decision" | "learning" | "observation";
18→  readonly text: string;
19→  readonly weight: number;
20→  readonly embedding?: number[];
21→};
22→
23→export type CachedCandidatePool = {
24→  readonly decisions: CandidateItem[];
25→  readonly learnings: CandidateItem[];
26→  readonly observations: CandidateItem[];
27→  readonly populatedAt: number;
28→};
29→
30→export type ContextCache = {
31→  get(workspaceId: string): CachedCandidatePool | undefined;
32→  set(workspaceId: string, pool: CachedCandidatePool): void;
33→  has(workspaceId: string): boolean;
34→};
35→
36→// ---------------------------------------------------------------------------
37→// Factory
38→// ---------------------------------------------------------------------------
39→
40→export function createContextCache(ttlSeconds: number): ContextCache {
41→  // Per-handler-instance cache (created via factory in createAnthropicProxyHandler).
42→  // TTL provides eventual consistency with the graph — stale reads are acceptable
43→  // since context injection is best-effort. Cache stampede on cold start is fine:
44→  // concurrent requests for the same workspace may each populate, but the last
45→  // write wins and subsequent reads serve from cache. Workspace cardinality is
46→  // low enough that unbounded Map growth is not a concern.
47→  const store = new Map<string, CachedCandidatePool>();
48→  const ttlMs = ttlSeconds * 1000;
49→
50→  function isExpired(pool: CachedCandidatePool): boolean {
51→    return Date.now() - pool.populatedAt > ttlMs;
52→  }
53→
54→  return {
55→    get(workspaceId: string): CachedCandidatePool | undefined {
56→      const cached = store.get(workspaceId);
57→      if (!cached) return undefined;
58→      if (isExpired(cached)) {
59→        store.delete(workspaceId);
60→        return undefined;
61→      }
62→      return cached;
63→    },
64→
65→    set(workspaceId: string, pool: CachedCandidatePool): void {
66→      store.set(workspaceId, pool);
67→    },
68→
69→    has(workspaceId: string): boolean {
70→      const cached = store.get(workspaceId);
71→      if (!cached) return false;
72→      if (isExpired(cached)) {
73→        store.delete(workspaceId);
74→        return false;
75→      }
76→      return true;
77→    },
78→  };
79→}
80→

